beforeJsCode:
var modalId = "modalSelectorTicket";

if(!document.getElementById(modalId)){
    var html = ''
    + '<div id="'+modalId+'" style="position:fixed;inset:0;background:rgba(0,0,0,.45);z-index:99999;display:none;">'
    + '  <div style="position:absolute;left:3%;top:3%;width:94%;height:94%;background:#fff;border-radius:14px;overflow:hidden;box-shadow:0 20px 50px rgba(0,0,0,.35);">'
    + '    <div style="height:52px;padding:12px 16px;background:#0b5cab;color:#fff;font-weight:600;">'
    + '      Seleccionar ticket'
    + '      <button type="button" id="cerrarSelectorTicket" style="float:right;background:#fff;color:#0b5cab;border:none;border-radius:8px;padding:6px 10px;">Cerrar</button>'
    + '    </div>'
    + '    <iframe id="iframeSelectorTicket" src="" style="width:100%;height:calc(100% - 52px);border:0;"></iframe>'
    + '  </div>'
    + '</div>';

    document.body.insertAdjacentHTML("beforeend", html);

    document.getElementById("cerrarSelectorTicket").onclick = function(){
        document.getElementById(modalId).style.display = "none";
        document.getElementById("iframeSelectorTicket").src = "about:blank";
    };
}

document.getElementById("iframeSelectorTicket").src = "tickets_atencion_domicilio_list.php?selector_ticket=1";
document.getElementById(modalId).style.display = "block";

return false;
